1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	
14	type Scenario = {
15	  customer: { yearsWithMHPCO: number };
16	  steps: Array<{ op: "quote"; items: Item[] }>;
17	};
18	
19	type QuoteResult = { premium: number };
20	
21	const COMPONENT_BLOCK_SIZE = 3;
22	const COMPONENT_BLOCK_PREMIUM = 60;
23	
24	const basePremiumFor = (items: Item[]): number => {
25	  if (items.length === COMPONENT_BLOCK_SIZE && items.every((item) => item.type === "rune")) {
26	    return COMPONENT_BLOCK_PREMIUM;
27	  }
28	  return items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
29	};
30	
31	const quotePremium = (items: Item[]): QuoteResult => {
32	  const base = basePremiumFor(items);
33	  return { premium: base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE };
34	};
35	
36	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
37	  const results = scenario.steps.map((step) => quotePremium(step.items));
38	  return { results };
39	};
